// Example function to dynamically update cart items (can be expanded)
document.addEventListener('DOMContentLoaded', () => {
    const cartItems = document.getElementById('cart-items');
    const totalPriceDisplay = document.getElementById('total-price');

    // Sample data for demonstration purposes
    const sampleCartData = [
        { product: 'T-Shirt (Blue)', quantity: 1, price: 20.0 },
    ];

    // Populate the table with cart items and calculate total price
    let totalPrice = 0;

    sampleCartData.forEach(item => {
        const row = document.createElement('tr');

        const productCell = document.createElement('td');
        productCell.textContent = item.product;
        row.appendChild(productCell);

        const quantityCell = document.createElement('td');
        quantityCell.textContent = item.quantity;
        row.className = 'quantity';
        row.appendChild(quantityCell);

        const totalCell = document.createElement('td');
        totalCell.textContent = `$${item.price.toFixed(2)}`;
        totalPrice += item.price * item.quantity;
        row.appendChild(totalCell);

        cartItems.appendChild(row);
    });

    // Display the final total price
    totalPriceDisplay.textContent = `Total: $${totalPrice.toFixed(2)}`;
});
```

