### Step 4: Adding Dynamic Data

If you want to dynamically add items from a cart, you can modify the JavaScript as follows:

```javascript
document.addEventListener('DOMContentLoaded', () => {
    const itemTemplate = document.querySelector('.cart-item').cloneNode(true);
    const itemList = document.getElementById('item-list');
    const payNowBtn = document.getElementById('pay-now-btn');

    // Example items in JSON format (replace this with actual data from your application state)
    const cartItems = [
        { id: 1, name: 'Item 1', price: 9.99, imageUrl: 'https://via.placeholder.com/50x50' },
        { id: 2, name: 'Item 2', price: 19.99, imageUrl: 'https://via.placeholder.com/50x50' }
    ];

    cartItems.forEach(item => {
        const itemEl = itemTemplate.cloneNode(true);
        itemEl.querySelector('img').src = item.imageUrl;
        itemEl.querySelector('.cart-item h4').innerText = item.name;
        itemEl.querySelector('.cart-item p').innerText = `$${item.price.toFixed(2)}`;
        itemList.appendChild(itemEl);
    });

    // Simulating payment action with an alert box
